"use client";

import { ChangeEvent, useRef, useState } from "react";
import { useRouter } from "next/navigation";
import { AlertCircle, ClipboardCheck, FileText, Link2, Loader2, Play, ShieldCheck, Sparkles, Upload } from "lucide-react";
import { BrandLockup } from "@/components/brand";
import type { CheckReport } from "@/lib/types";

type SampleInput = {
  jdText: string;
  resumeText: string;
  evidenceText: string;
};

export function HomeClient() {
  const router = useRouter();
  const [jdText, setJdText] = useState("");
  const [resumeText, setResumeText] = useState("");
  const [jdUrl, setJdUrl] = useState("");
  const [jdSourceUrl, setJdSourceUrl] = useState("");
  const [resumeFileName, setResumeFileName] = useState("");
  const [importError, setImportError] = useState("");
  const [isImportingJd, setIsImportingJd] = useState(false);
  const [isReadingResume, setIsReadingResume] = useState(false);
  const [isSampleLoaded, setIsSampleLoaded] = useState(false);
  const [isScanning, setIsScanning] = useState(false);
  const fileInputRef = useRef<HTMLInputElement | null>(null);
  const canStart = jdText.trim().length > 40 && resumeText.trim().length > 30;
  const hasExternalSource = Boolean(jdSourceUrl || resumeFileName);

  async function loadSample() {
    const res = await fetch("/api/report");
    const data = (await res.json()) as SampleInput;
    setJdText(data.jdText);
    setResumeText(data.resumeText);
    setJdUrl("");
    setJdSourceUrl("");
    setResumeFileName("");
    setImportError("");
    setIsSampleLoaded(true);
  }

  async function importJdFromUrl() {
    if (!jdUrl.trim() || isImportingJd) return;
    setIsImportingJd(true);
    setImportError("");
    try {
      const res = await fetch("/api/import/jd", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({ url: jdUrl })
      });
      const data = (await res.json()) as { text?: string; sourceUrl?: string; error?: string };
      if (!res.ok || !data.text) {
        setImportError(data.error || "岗位链接读取失败，请复制 JD 文本。");
        return;
      }
      setJdText(data.text);
      setJdSourceUrl(data.sourceUrl || jdUrl);
      setIsSampleLoaded(false);
    } finally {
      setIsImportingJd(false);
    }
  }

  async function readResumeFile(event: ChangeEvent<HTMLInputElement>) {
    const file = event.target.files?.[0];
    if (!file) return;
    setIsReadingResume(true);
    setImportError("");
    try {
      const text = file.type === "application/pdf" || file.name.toLowerCase().endsWith(".pdf")
        ? await extractPdfText(file)
        : await file.text();
      const cleaned = text.replace(/\s+/g, " ").trim();
      if (cleaned.length < 30) {
        setImportError("这份文件没有读到足够简历文字，请换 PDF/TXT 或直接粘贴。");
        return;
      }
      setResumeText(cleaned.slice(0, 8000));
      setResumeFileName(file.name);
      setIsSampleLoaded(false);
    } catch (error) {
      const detail = error instanceof Error ? error.message.slice(0, 90) : "未知错误";
      setImportError(`简历文件读取失败：${detail}。请换成可复制文字的 PDF/TXT。`);
    } finally {
      setIsReadingResume(false);
      event.target.value = "";
    }
  }

  async function startCheck() {
    if (!canStart || isScanning) return;
    setIsScanning(true);
    const inputSource = isSampleLoaded ? "sample" : jdSourceUrl && resumeFileName ? "mixed" : jdSourceUrl ? "jd-url" : resumeFileName ? "resume-file" : "paste";
    const res = await fetch("/api/report", {
      method: "POST",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify({ jdText, resumeText, jdSourceUrl, resumeFileName, inputSource, useSample: isSampleLoaded })
    });
    const report = (await res.json()) as CheckReport;
    window.setTimeout(() => router.push(`/result/${report.id}`), 900);
  }

  return (
    <main className="app-shell" data-visual-lane="operational-dashboard / blueprint-lab 混合。" data-hero-composition="precheck-scanner" data-hero-text="贴岗位，贴简历，30 秒看能不能投">
      <Header />
      <section className="import-console panel" data-testid="import-console">
        <div className="import-title">
          <span className="status-pill blue">完整导入台</span>
          <h2>不用整理格式，先把岗位和简历拉进来</h2>
          <p>支持粘贴 JD、公开岗位链接、PDF/TXT 简历。导入后马上进入可证明性体检。</p>
        </div>
        <div className="import-controls">
          <label className="url-import">
            <span><Link2 size={16} />岗位链接</span>
            <input data-testid="jd-url-input" value={jdUrl} onChange={(event) => setJdUrl(event.target.value)} placeholder="粘贴公开岗位详情页 URL" />
          </label>
          <button className="secondary-button min-h-11 min-w-11" onClick={importJdFromUrl} disabled={isImportingJd || !jdUrl.trim()} data-testid="import-jd-url-button" type="button">
            {isImportingJd ? <Loader2 className="spin" size={18} /> : <Link2 size={18} />}
            {isImportingJd ? "正在拉取" : "拉取 JD"}
          </button>
          <input ref={fileInputRef} className="hidden-file-input" type="file" accept=".pdf,.txt,.md,text/plain,application/pdf" onChange={readResumeFile} data-testid="resume-file-input" />
          <button className="secondary-button min-h-11 min-w-11" onClick={() => fileInputRef.current?.click()} disabled={isReadingResume} data-testid="upload-resume-button" type="button">
            {isReadingResume ? <Loader2 className="spin" size={18} /> : <Upload size={18} />}
            {isReadingResume ? "正在读取" : "上传简历 PDF"}
          </button>
        </div>
        <div className="import-receipts" data-testid="import-receipts">
          <span className={jdSourceUrl ? "receipt-chip done" : "receipt-chip"}>{jdSourceUrl ? "JD 已从链接拉取" : jdText ? "JD 已粘贴" : "等待 JD"}</span>
          <span className={resumeFileName ? "receipt-chip done" : "receipt-chip"}>{resumeFileName ? `简历文件：${resumeFileName}` : resumeText ? "简历已粘贴" : "等待简历"}</span>
          <span className={hasExternalSource ? "receipt-chip done" : "receipt-chip"}>{hasExternalSource ? "真实导入来源已记录" : "可用演示样例快速体验"}</span>
        </div>
        {importError ? <div className="inline-error" data-testid="import-error"><AlertCircle size={16} />{importError}</div> : null}
      </section>
      <section className="hero-grid" data-testid="screen-home">
        <InputPanel
          icon={<ClipboardCheck size={20} />}
          title="第一步：粘贴岗位描述"
          label={jdText ? "岗位信息已就绪" : "等待岗位信息"}
          value={jdText}
          onChange={(value) => {
            setJdText(value);
            setJdSourceUrl("");
            setIsSampleLoaded(false);
          }}
          hint="把岗位 JD 粘贴到这里。"
          footer={`已输入 ${jdText.length} 字`}
          testId="jd-input"
        />
        <ScannerPanel isScanning={isScanning} canStart={canStart} onStart={startCheck} onSample={loadSample} isSampleLoaded={isSampleLoaded} />
        <InputPanel
          icon={<FileText size={20} />}
          title="第二步：粘贴或上传简历"
          label={resumeText ? "简历信息已就绪" : "等待简历信息"}
          value={resumeText}
          onChange={(value) => {
            setResumeText(value);
            setResumeFileName("");
            setIsSampleLoaded(false);
          }}
          hint="上传 PDF/TXT，或直接粘贴简历文本。"
          footer={`已输入 ${resumeText.length} 字`}
          testId="resume-input"
        />
      </section>
    </main>
  );
}

function Header() {
  return (
    <header className="topbar">
      <BrandLockup />
      <div className="boundary-note" data-testid="proof-boundary-note">
        只判断“可证明性”，不验证经历真实性
      </div>
    </header>
  );
}

async function extractPdfText(file: File) {
  const pdfjs = await import("pdfjs-dist");
  pdfjs.GlobalWorkerOptions.workerSrc = "/vendor/pdf.worker.min.mjs";
  const buffer = await file.arrayBuffer();
  const doc = await pdfjs.getDocument({ data: buffer }).promise;
  const chunks: string[] = [];
  const maxPages = Math.min(doc.numPages, 8);
  for (let index = 1; index <= maxPages; index += 1) {
    const page = await doc.getPage(index);
    const content = await page.getTextContent();
    chunks.push(content.items.map((item) => ("str" in item ? item.str : "")).join(" "));
  }
  return chunks.join("\n");
}

function InputPanel(props: {
  icon: React.ReactNode;
  title: string;
  label: string;
  value: string;
  onChange: (value: string) => void;
  hint: string;
  footer: string;
  testId: string;
}) {
  const ready = props.value.trim().length > 0;
  return (
    <section className="panel input-panel">
      <div className="panel-head">
        <div className="panel-title">{props.icon}{props.title}</div>
        <span className={ready ? "status-pill green" : "status-pill neutral"}>{props.label}</span>
      </div>
      <textarea
        data-testid={props.testId}
        value={props.value}
        onChange={(event) => props.onChange(event.target.value)}
        aria-label={props.title}
      />
      {!ready ? <div className="input-hint">{props.hint}</div> : null}
      <div className="panel-foot">
        <span>{props.footer}</span>
        <span className={ready ? "ready-word" : ""}>{ready ? "完成" : "未完成"}</span>
      </div>
    </section>
  );
}

function ScannerPanel(props: {
  isScanning: boolean;
  canStart: boolean;
  isSampleLoaded: boolean;
  onStart: () => void;
  onSample: () => void;
}) {
  const cards = [
    ["用户调研：调研样本和结论", "缺少证据", "red"],
    ["活动运营：个人贡献边界", "证据较弱", "yellow"],
    ["数据复盘：结果指标", "缺少证据", "red"]
  ];
  return (
    <section className={`panel scanner-panel ${props.isScanning ? "is-scanning" : ""}`} data-testid="scanner-section">
      <div>
        <div className="scanner-kicker">求职安检机</div>
        <h2>岗位要求和简历声明正在逐条对齐</h2>
      </div>
      <div className="scanner-gate" data-testid="scanner-gate">
        {cards.map(([title, label, tone]) => (
          <div className="scan-card" key={title}>
            <span>{title}</span>
            <b className={`evidence-badge ${tone}`}>{label}</b>
          </div>
        ))}
        <div className="scan-beam" data-testid="scan-beam" />
      </div>
      <div className="agent-row">
        {["岗位解析", "简历声明", "证据核验", "招聘官分身", "行动建议"].map((item, index) => (
          <div className={index < 2 || props.isScanning ? "agent-node active" : "agent-node"} key={item}>
            <ShieldCheck size={16} />
            <span>{item}</span>
          </div>
        ))}
      </div>
      <div className="scanner-actions">
        <button className="secondary-button min-h-11 min-w-11" onClick={props.onSample} data-testid="demo-sample-button" type="button">
          <Sparkles size={18} />
          {props.isSampleLoaded ? "已载入演示样例" : "使用演示样例"}
        </button>
        <button className="primary-button min-h-11 min-w-11" onClick={props.onStart} disabled={!props.canStart || props.isScanning} data-testid="start-check-button" data-cta-primary="投前体检" type="button">
          <Play size={18} />
          {props.isScanning ? "正在体检" : "投前体检"}
        </button>
      </div>
    </section>
  );
}
